function handler.onGameStateInfo(data)
    local builder = DataBuilder.new():fromData(data)
    local state = builder:getNumberParam("state")
    GameClient.GameStatus = state
    LogUtil.log("onGameStateInfo " .. state)

    if state == Define.GameStatus.WaitGameStart then
        --startWaitGameStartCountDown()
    elseif state == Define.GameStatus.GameRunning then
        ClientHelper.putFloatPrefs("FloatNumberTimeSpeed", 1.0)
        ClientHelper.putIntPrefs("ShowFloatNumberTime", GameConfig.showFloatNumberTime)
        ChampionShipConfig:removeCageBlockRegion()
        LogUtil.log("onGameStateInfo GameStatus.GameRunning")
    end
end

function handler.onWaitGameStartCountDown(data)
    local builder = DataBuilder.new():fromData(data)
    local time = builder:getNumberParam("time")
    ClientHelper.putFloatPrefs("FloatNumberTimeSpeed", ChampionShipConfig.floatNumberSpeed)
    ClientHelper.putIntPrefs("ShowFloatNumberTime", ChampionShipConfig.floatNumberTime)
    WorldImageRender.Instance():removeAllFloatNumber()
    WorldImageRender.Instance():addFloatNumber(tostring(time), ChampionShipConfig.floatNumberPos,
            ChampionShipConfig.floatNumberScale, 6, 0)
end

return handler